import hashlib
import pickle
import os
import subprocess
from django.shortcuts import render, HttpResponse
from django.views.decorators.csrf import csrf_exempt
import requests
from django.db import connection

@csrf_exempt
def user_search(request):
    name = request.GET.get('name', '')
    with connection.cursor() as cur:
        cur.execute(f"SELECT * FROM users WHERE name = '{name}'")
        rows = cur.fetchall()
    return HttpResponse(str(rows))

def profile_image(request):
    user_url = request.GET.get('url')
    r = requests.get(user_url)
    return HttpResponse(r.content, content_type='image/png')

def run_calc(request):
    expr = request.GET.get('expr')
    result = eval(expr)
    return HttpResponse(str(result))

def hash_pw(password):
    return hashlib.md5(password.encode()).hexdigest()

def restore_session(request):
    blob = request.body
    session = pickle.loads(blob)
    return HttpResponse(repr(session))

def export(request):
    fmt = request.GET.get('fmt', 'csv')
    subprocess.run(f'./export.sh {fmt}', shell=True)
    return HttpResponse('ok')
